package com.knowledgegraph.app

import android.app.Application
import android.util.Log

class KgApplication : Application() {
    override fun onCreate() {
        super.onCreate()
        try {
            System.loadLibrary("clojure_engine")
            System.loadLibrary("lisp_engine")
            System.loadLibrary("mercury_engine")
            Log.i("KgApplication", "Native libraries loaded successfully")
        } catch (e: UnsatisfiedLinkError) {
            Log.e("KgApplication", "Failed to load native libs", e)
        }
    }
}

package com.knowledgegraph.app

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.viewModels
import androidx.compose.runtime.*
import androidx.lifecycle.lifecycleScope
import com.knowledgegraph.app.ui.screens.*
import com.knowledgegraph.app.ui.theme.AppTheme
import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import com.knowledgegraph.app.viewmodel.GraphViewModel
import com.knowledgegraph.app.viewmodel.SecurityViewModel
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch

class MainActivity : ComponentActivity() {

    private val graphViewModel: GraphViewModel by viewModels {
        GraphViewModelFactory(applicationContext)
    }
    private val securityViewModel: SecurityViewModel by viewModels()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Start auto-lock checker loop
        lifecycleScope.launch {
            while (true) {
                delay(10_000L)
                securityViewModel.checkAutoLock()
            }
        }

        setContent {
            AppTheme {
                val isLocked by securityViewModel.isLocked.collectAsState()

                if (isLocked) {
                    BiometricLockScreen(
                        securityViewModel = securityViewModel,
                        activity = this@MainActivity
                    )
                } else {
                    MainScreen(
                        viewModel = graphViewModel,
                        onUserInteraction = { securityViewModel.resetSessionTimer() }
                    )
                }
            }
        }
    }

    override fun onResume() {
        super.onResume()
        securityViewModel.checkAutoLock()
    }

    override fun onUserInteraction() {
        super.onUserInteraction()
        securityViewModel.resetSessionTimer()
    }
}

class GraphViewModelFactory(private val context: Context) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(GraphViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return GraphViewModel(context) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

package com.knowledgegraph.app.bridge

external object ClojureBridge {
    @JvmStatic external fun updateGraph(payload: String): String
    @JvmStatic external fun getClojureVersion(): String
    @JvmStatic external fun getPluginSuggestions(payload: String): String
    @JvmStatic external fun togglePlugin(pluginId: String): String
    @JvmStatic external fun searchGraph(payload: String): String

    fun safeUpdateGraph(payload: String): String = try {
        updateGraph(payload)
    } catch (e: UnsatisfiedLinkError) {
        "{\"error\":\"Clojure bridge not available. Please check the installation.\",\"details\":\"${e.message}\"}"
    }

    fun safeGetPluginSuggestions(payload: String): String = try {
        getPluginSuggestions(payload)
    } catch (e: UnsatisfiedLinkError) {
        "[{\"plugin-id\":\"error\",\"label\":\"Error\",\"result\":{\"error\":\"Bridge error\",\"details\":\"${e.message}\"}}]"
    }

    fun safeTogglePlugin(pluginId: String): String = try {
        togglePlugin(pluginId)
    } catch (e: UnsatisfiedLinkError) {
        "{\"error\":\"Bridge error\",\"details\":\"${e.message}\"}"
    }

    fun safeSearchGraph(query: String, graphJson: String): String = try {
        val edn = """{:graph "${graphJson.replace("\"", "\\\"")}", :query "$query"}"""
        searchGraph(edn)
    } catch (e: UnsatisfiedLinkError) {
        "[{\"error\":\"Bridge error\",\"details\":\"${e.message}\"}]"
    }
}

package com.knowledgegraph.app.bridge

external object LispBridge {
    @JvmStatic external fun getLispVersion(): String

    fun runInferenceWithCorrections(facts: String, corrections: String): String {
        val payload = """
            (require 'runtime.lisp-bridge)
            (runtime.lisp-bridge/run-lisp-inference-with-corrections "$facts" "$corrections")
        """.trimIndent()
        return ClojureBridge.safeUpdateGraph(payload)
    }

    fun safeEvaluateRule(rule: String): String = try {
        val payload = """
            (require 'runtime.lisp-bridge)
            (runtime.lisp-bridge/evaluate-lisp-rule "$rule")
        """.trimIndent()
        ClojureBridge.safeUpdateGraph(payload)
    } catch (e: UnsatisfiedLinkError) {
        "(error \"Lisp bridge not available: ${e.message}\")"
    }
}

package com.knowledgegraph.app.bridge

external object MercuryBridge {
    @JvmStatic external fun checkConsistency(graphJson: String): Boolean
    @JvmStatic external fun runInference(graphJson: String): String
    @JvmStatic external fun getMercuryVersion(): String

    fun safeCheckConsistency(graphJson: String): Boolean = try {
        checkConsistency(graphJson)
    } catch (e: UnsatisfiedLinkError) {
        // In a real app, you'd want to log this error
        e.printStackTrace()
        false
    }

    fun safeRunInference(graphJson: String): String = try {
        runInference(graphJson)
    } catch (e: UnsatisfiedLinkError) {
        // In a real app, you'd want to log this error
        e.printStackTrace()
        "{\"error\":\"inference_error\", \"details\":\"${e.message}\"}"
    }
}

