@Composable
fun DiagnosticsOverlay(viewModel: GraphViewModel, modifier: Modifier = Modifier) {
    val context = LocalContext.current
    var time by remember { mutableStateOf(System.currentTimeMillis()) }
    var clojureVersion by remember { mutableStateOf("Loading...") }
    var lispVersion by remember { mutableStateOf("Loading...") }
    var mercuryVersion by remember { mutableStateOf("Loading...") }

    LaunchedEffect(Unit) {
        while (true) {
            delay(1000)
            time = System.currentTimeMillis()
        }
    }

    LaunchedEffect(true) {
        withContext(Dispatchers.IO) {
            try {
                clojureVersion = ClojureBridge.getClojureVersion()
                lispVersion = LispBridge.getLispVersion()
                mercuryVersion = MercuryBridge.getMercuryVersion()
            } catch (e: UnsatisfiedLinkError) {
                clojureVersion = "Unavailable"
                lispVersion = "Unavailable"
                mercuryVersion = "Unavailable"
            }
        }
    }

    val scrollState = rememberScrollState()
    val graphState by viewModel.graphState.collectAsState()
    val interactionLog by viewModel.interactionLog.collectAsState()
    val forgottenNodes = viewModel.getForgottenNodes()
    val showWeights by viewModel.showEdgeWeights.collectAsState()

    Column(
        modifier = modifier
            .fillMaxWidth()
            .background(MaterialTheme.colorScheme.surface.copy(alpha = 0.9f))
            .padding(12.dp)
            .verticalScroll(scrollState),
        horizontalAlignment = Alignment.Start
    ) {
        Text("Diagnostics", fontWeight = FontWeight.Bold, color = Color.Magenta)
        Text("Current Time: $time")
        Text("Clojure Bridge: $clojureVersion")
        Text("Lisp Bridge: $lispVersion")
        Text("Mercury Bridge: $mercuryVersion")

        Spacer(modifier = Modifier.height(8.dp))
        Text("Node Count: ${graphState.nodes.size}")
        Text("Edge Count: ${graphState.edges.size}")

        Spacer(modifier = Modifier.height(8.dp))
        Text("Recent Interactions:")
        interactionLog.takeLast(5).reversed().forEach { id ->
            val label = graphState.nodes.find { it.id == id }?.label ?: "Unknown"
            Text("• [$id] $label")
        }

        Spacer(modifier = Modifier.height(8.dp))
        Text("Forgotten Nodes:")
        forgottenNodes.take(5).forEach { id ->
            val label = graphState.nodes.find { it.id == id }?.label ?: "Unknown"
            Text("• [$id] $label")
        }

        Spacer(modifier = Modifier.height(12.dp))
        Button(onClick = { viewModel.toggleEdgeWeightVisibility() }) {
            Text(if (showWeights) "Hide Edge Weights" else "Show Edge Weights")
        }

        Spacer(modifier = Modifier.height(8.dp))
        Button(onClick = {
            val success = viewModel.exportForgottenNodes(context)
            Toast.makeText(
                context,
                if (success) "Exported to forgotten_nodes.edn" else "Export failed",
                Toast.LENGTH_SHORT
            ).show()
        }) {
            Text("Export Forgotten Nodes")
        }

        Spacer(modifier = Modifier.height(12.dp))
        Text("Plugins", fontWeight = FontWeight.Bold)
        val suggestions = viewModel.fetchPluginSuggestions()
        suggestions.forEach {
            Text("• $it")
        }

        Spacer(modifier = Modifier.height(8.dp))
        Button(onClick = {
            val messages = viewModel.executePluginActions()
            Toast.makeText(context, messages.joinToString("\n"), Toast.LENGTH_SHORT).show()
        }) {
            Text("Apply Plugin Actions")
        }
    }
}

package com.knowledgegraph.app.model

data class GraphState(
    val nodes: List<GraphNode> = emptyList(),
    val edges: List<GraphEdge> = emptyList()
) {
    fun toJson(): String {
        val nodeJson = nodes.joinToString(",", prefix = "[", postfix = "]") {
            """{"id":"${it.id}","label":"${it.label}","type":"${it.type}"}"""
        }
        val edgeJson = edges.joinToString(",", prefix = "[", postfix = "]") {
            """{"source":"${it.source}","target":"${it.target}","relation":"${it.relation}"}"""
        }
        return """{"nodes":$nodeJson,"edges":$edgeJson}"""
    }
}

package com.knowledgegraph.app.services

import android.content.Context
import android.os.CancellationSignal
import android.widget.Toast
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import androidx.fragment.app.FragmentActivity

class BiometricHelper(private val context: Context) {
    private var cancellationSignal: CancellationSignal? = null

    fun isBiometricAvailable(): Boolean {
        val biometricManager = BiometricManager.from(context)
        return biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_WEAK) ==
                BiometricManager.BIOMETRIC_SUCCESS
    }

    fun authenticate(activity: FragmentActivity, onSuccess: () -> Unit, onError: () -> Unit) {
        val executor = ContextCompat.getMainExecutor(context)
        val biometricPrompt = BiometricPrompt(activity, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    onSuccess()
                }

                override fun onAuthenticationFailed() {
                    Toast.makeText(context, "Biometric failed", Toast.LENGTH_SHORT).show()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    onError()
                }
            })

        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Unlock KnowledgeGraph")
            .setSubtitle("Authenticate to continue")
            .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_WEAK)
            .setNegativeButtonText("Cancel")
            .build()

        cancellationSignal = CancellationSignal()
        biometricPrompt.authenticate(promptInfo)
    }

    fun cancel() {
        cancellationSignal?.cancel()
    }
}

package com.knowledgegraph.app.services

import com.knowledgegraph.app.bridge.ClojureBridge
import com.knowledgegraph.app.bridge.LispBridge
import com.knowledgegraph.app.bridge.MercuryBridge
import com.knowledgegraph.app.model.GraphState
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext

object BridgeRouter {

    suspend fun evaluateClojure(graphJson: String): String = withContext(Dispatchers.IO) {
        return@withContext ClojureBridge.updateGraph(graphJson)
    }

    suspend fun evaluateLisp(ruleText: String): String = withContext(Dispatchers.IO) {
        return@withContext LispBridge.evaluateRule(ruleText)
    }

    suspend fun runMercury(graph: GraphState): String = withContext(Dispatchers.IO) {
        val factData = GraphService.toFactFile(graph)
        val tempFile = kotlin.io.path.createTempFile("facts_", ".txt")
        tempFile.toFile().writeText(factData)

        val process = ProcessBuilder("./mercury_run", tempFile.toAbsolutePath().toString())
            .redirectErrorStream(true)
            .start()

        val result = process.inputStream.bufferedReader().readText()
        process.waitFor()
        return@withContext result
    }
}

package com.knowledgegraph.services

import com.knowledgegraph.model.GraphNode
import com.knowledgegraph.model.GraphEdge
import edu.stanford.nlp.pipeline.StanfordCoreNLP
import java.util.*

/**
 * Service for performing contextual search and pattern-based graph traversal.
 * Uses edge types, node metadata, and local tags to build context-aware queries.
 */
class ContextualSearchService(private val graphService: GraphService) {

    private val pipeline: StanfordCoreNLP

    init {
        val props = Properties()
        props.setProperty("annotators", "tokenize,ssplit,pos,lemma,ner,depparse")
        pipeline = StanfordCoreNLP(props)
    }

    /**
     * Search nodes by approximate label with optional context tags.
     */
    fun searchNodes(labelQuery: String, contextTags: Set<String> = emptySet()): List<GraphNode> {
        return graphService.getAllNodes().filter { node ->
            val labelMatch = node.label.contains(labelQuery, ignoreCase = true)
            val tagMatch = contextTags.isEmpty() || contextTags.intersect(node.tags).isNotEmpty()
            labelMatch && tagMatch
        }
    }

    /**
     * Explore nodes connected to a given node, filtered by relationship type or tag context.
     */
    fun exploreContext(nodeId: String, relationshipTypes: Set<String> = emptySet(), tagFilters: Set<String> = emptySet()): List<GraphNode> {
        val relatedEdges = graphService.getEdgesForNode(nodeId)
        val filteredEdges = relatedEdges.filter { edge ->
            relationshipTypes.isEmpty() || relationshipTypes.contains(edge.type)
        }

        return filteredEdges.mapNotNull { edge ->
            val neighborId = if (edge.source == nodeId) edge.target else edge.source
            val neighbor = graphService.getNodeById(neighborId)
            if (neighbor != null && (tagFilters.isEmpty() || tagFilters.intersect(neighbor.tags).isNotEmpty())) {
                neighbor
            } else null
        }
    }

    /**
     * Retrieve all paths from a node within N depth and filter by context.
     */
    fun findPaths(nodeId: String, depth: Int = 2, tagContext: Set<String> = emptySet()): List<List<GraphNode>> {
        val visited = mutableSetOf<String>()
        val results = mutableListOf<List<GraphNode>>()

        fun dfs(currentId: String, path: List<GraphNode>) {
            if (path.size > depth) return
            visited.add(currentId)

            val node = graphService.getNodeById(currentId) ?: return
            if (tagContext.isEmpty() || tagContext.intersect(node.tags).isNotEmpty()) {
                results.add(path + node)
            }

            val neighbors = exploreContext(currentId)
            for (neighbor in neighbors) {
                if (!visited.contains(neighbor.id)) {
                    dfs(neighbor.id, path + node)
                }
            }
        }

        dfs(nodeId, emptyList())
        return results
    }

    fun semanticSearch(query: String): List<GraphNode> {
        val document = pipeline.process(query)
        val entities = document.sentences().flatMap { it.mentions() }
        val matchingNodes = entities.mapNotNull { entity ->
            graphService.getAllNodes().find { node ->
                node.label.equals(entity.text(), ignoreCase = true)
            }
        }

        val exploredNodes = mutableSetOf<GraphNode>()
        for (sentence in document.sentences()) {
            val dependencyParse = sentence.dependencyParse()
            dependencyParse.edgeList().forEach { edge ->
                val sourceNode = graphService.getNodeByLabel(edge.source().word())
                val targetNode = graphService.getNodeByLabel(edge.target().word())

                if (sourceNode != null && targetNode != null) {
                    val relationshipType = edge.relation().toString()
                    val newEdge = GraphEdge(
                        source = sourceNode.id,
                        target = targetNode.id,
                        type = relationshipType,
                        weight = 1.0
                    )
                    graphService.addEdge(newEdge)
                    exploredNodes.add(sourceNode)
                    exploredNodes.add(targetNode)
                }
            }
        }

        return (matchingNodes + exploredNodes).distinct()
    }
}

package com.knowledgegraph.app.services

import android.content.Context
import com.knowledgegraph.app.model.GraphState
import kotlinx.serialization.encodeToString
import kotlinx.serialization.json.Json
import java.io.File

class FileIOService(private val context: Context) {

    private val baseDir = context.filesDir

    fun saveGraph(graphState: GraphState, filename: String): Boolean {
        return try {
            val json = Json.encodeToString(graphState)
            val file = File(baseDir, filename)
            file.writeText(json)
            true
        } catch (e: Exception) {
            e.printStackTrace()
            false
        }
    }

    fun loadGraph(filename: String): GraphState? {
        return try {
            val file = File(baseDir, filename)
            if (!file.exists()) return null
            val json = file.readText()
            Json.decodeFromString<GraphState>(json)
        } catch (e: Exception) {
            e.printStackTrace()
            null
        }
    }

    fun exportGraph(graphState: GraphState, format: String, path: String): Boolean {
        // TODO: Implement different export formats (e.g., GraphML, GEXF)
        return saveGraph(graphState, path)
    }

    fun importGraph(path: String): GraphState? {
        // TODO: Implement different import formats
        return loadGraph(path)
    }
}

package com.knowledgegraph.app.services

import android.content.Context
import android.net.Uri
import android.util.Log
import java.io.File
import com.knowledgegraph.app.services.BridgeRouter

class FileImportManager(private val context: Context, private val bridgeRouter: BridgeRouter) {

    var enableOCR = true

    fun importFileFromUri(uri: Uri) {
        val path = FileUtils.getPathFromUri(context, uri)
        if (path != null) {
            val file = File(path)
            if (file.exists()) {
                importFile(file)
            } else {
                Log.w("FileImportManager", "File does not exist: $path")
            }
        } else {
            Log.w("FileImportManager", "Failed to resolve file path from URI: $uri")
        }
    }

    private fun isImageFile(file: File): Boolean {
        val ext = file.extension.lowercase()
        return ext in listOf("jpg", "jpeg", "png")
    }

    private fun isTextFile(file: File): Boolean {
        val ext = file.extension.lowercase()
        return ext in listOf("txt", "md", "markdown", "pdf")
    }

    fun importFile(file: File) {
        when {
            isImageFile(file) -> {
                Log.d("FileImportManager", "Routing image to Clojure (OCR=$enableOCR): ${file.absolutePath}")
                bridgeRouter.sendToClojure("extract-file-meta", file.absolutePath)
            }

            isTextFile(file) -> {
                Log.d("FileImportManager", "Routing text to Clojure: ${file.absolutePath}")
                bridgeRouter.sendToClojure("extract-file-meta", file.absolutePath)
            }

            else -> {
                Log.w("FileImportManager", "Unsupported file type: ${file.absolutePath}")
            }
        }
    }
}

package com.knowledgegraph.app.services

import android.util.Log
import com.knowledgegraph.app.bridge.ClojureBridge
import com.knowledgegraph.app.model.GraphEdge
import com.knowledgegraph.app.model.GraphNode
import com.knowledgegraph.app.model.GraphState
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.serialization.decodeFromString
import kotlinx.serialization.json.Json
import kotlinx.serialization.encodeToString

class GraphService {

    private val _graphState = MutableStateFlow(GraphState())
    val graphState: StateFlow<GraphState> = _graphState

    val latestGraphJson: String
        get() = Json.encodeToString(_graphState.value)

    fun getAllNodes(): List<GraphNode> = _graphState.value.nodes

    fun getNodeById(nodeId: String): GraphNode? =
        _graphState.value.nodes.find { it.id == nodeId }

    fun getNodeByLabel(label: String): GraphNode? =
        _graphState.value.nodes.find { it.label.equals(label, ignoreCase = true) }

    fun getEdgesForNode(nodeId: String): List<GraphEdge> =
        _graphState.value.edges.filter { it.source == nodeId || it.target == nodeId }

    fun addEdge(edge: GraphEdge) {
        val currentGraph = _graphState.value
        _graphState.value = currentGraph.copy(edges = currentGraph.edges + edge)
    }

    fun updateGraphFromText(noteInput: String) {
        val graphJson = latestGraphJson

        val payload = buildString {
            append("{:graph ")
            append("\"${graphJson.replace("\"", "\\\"")}\"")
            append(", :text ")
            append("\"${noteInput.replace("\"", "\\\"")}\"")
            append("}")
        }

        val resultJson = try {
            ClojureBridge.updateGraph(payload)
        } catch (e: Exception) {
            Log.e("GraphService", "Clojure updateGraph failed", e)
            "{\"nodes\":[],\"edges\":[]}"
        }

        Log.d("GraphService", "Updated Graph JSON:\n$resultJson")

        try {
            val newState = Json.decodeFromString<GraphState>(resultJson)
            _graphState.value = newState
        } catch (e: Exception) {
            Log.e("GraphService", "Failed to parse updated graph", e)
        }
    }
}

