import kotlinx.coroutines.flow.asStateFlow

class SecurityViewModel : ViewModel() {
    private val _isLocked = MutableStateFlow(true)
    val isLocked = _isLocked.asStateFlow()

    private val _lastUnlockTime = MutableStateFlow(System.currentTimeMillis())
    private val _sessionTimeoutMillis = 2 * 60 * 1000L // 2 minutes default

    fun unlock() {
        _isLocked.value = false
        _lastUnlockTime.value = System.currentTimeMillis()
    }

    fun lock() {
        _isLocked.value = true
    }

    fun checkAutoLock() {
        val now = System.currentTimeMillis()
        if (!_isLocked.value && now - _lastUnlockTime.value > _sessionTimeoutMillis) {
            _isLocked.value = true
        }
    }

    fun resetSessionTimer() {
        _lastUnlockTime.value = System.currentTimeMillis()
    }
}

std::string clojure_search_graph(const std::string& queryPayload) {
    static bool initialized = false;
    try {
        if (!initialized) {
            clojure::lang::RT::load("knowledge/interop");
            initialized = true;
        }
        auto* fn = clojure::lang::RT::var("knowledge.api", "run-semantic-search");
        auto* invoke = dynamic_cast<clojure::lang::IFn*>(fn);
        if (invoke) {
            auto* arg = new clojure::lang::String(queryPayload);
            auto* result = (*invoke)(arg);
            return result->toString();
        }
    } catch (const std::exception& e) {
        return "{\"error\":\"semantic_search_failed\", \"details\":\"" + std::string(e.what()) + "\"}";
    } catch (...) {
        return "{\"error\":\"semantic_search_failed\", \"details\":\"Unknown error\"}";
    }
    return "{\"error\":\"null_semantic_result\"}";
}

